var ent=msg.topic, state=msg.payload;
if(ent==='sensor.truenas_rsync_failed_paths'){flow.set('rsync_paths',state);return null;}
var rule=RULES[ent];
if(!rule)return null;
var fired=context.get('fired')||{};
var timers=context.get('timers')||{};
function test(){
  if(rule.op==='eq')return state===rule.val;
  if(rule.op==='in')return rule.val.indexOf(state)>=0;
  var n=parseFloat(state); if(isNaN(n))return false;
  if(rule.op==='gt')return n>rule.val;
  if(rule.op==='lt')return n<rule.val;
  return false;
}
var active=test();
var fname=(msg.ent&&msg.ent.attributes&&msg.ent.attributes.friendly_name)||ent.replace('sensor.truenas_disks_','');
function emit(nm){node.send({cat:rule.cat,sub:rule.sub,message:rule.m(state,nm),tag:rule.sub+'_'+ent});}
if(rule.for){
  if(active){
    if(fired[ent])return null;
    if(timers[ent])return null;
    var capName=fname;
    timers[ent]=setTimeout(function(){
      var tm=context.get('timers')||{};delete tm[ent];context.set('timers',tm);
      var fr=context.get('fired')||{};fr[ent]=true;context.set('fired',fr);
      emit(capName);
    },rule.for);
    context.set('timers',timers);
  }else{
    if(timers[ent]){clearTimeout(timers[ent]);delete timers[ent];context.set('timers',timers);}
    if(fired[ent]){fired[ent]=false;context.set('fired',fired);}
  }
}else{
  if(active){
    if(fired[ent])return null;
    fired[ent]=true;context.set('fired',fired);
    emit(fname);
  }else{
    if(fired[ent]){fired[ent]=false;context.set('fired',fired);}
  }
}
return null;

function dub(){return new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});}
function dhour(){return parseInt(new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',hour12:false}),10);}
function quiet(){var h=dhour();return (h>=22||h<7);}
function hhmm(ts){return new Date(ts).toLocaleTimeString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',minute:'2-digit'});}

if(msg.topic==='flush'){
  var held=context.get('held')||[];
  context.set('held',[]);
  if(!held.length)return null;
  var nots=[],logs=[];
  held.forEach(function(e){
    nots.push({title:e.title+' (triggered '+hhmm(e.firedAt)+')',message:e.message,ndata:e.ndata});
    logs.push({payload:dub()+'  [flush] '+e.title+' — '+e.message+'\n'});
  });
  node.send([nots,logs]);
  return null;
}

var cat=msg.cat, sub=msg.sub, message=msg.message;
if(!cat||!message)return null;
var title='['+cat+'] '+sub;
var tagsrc='ih_'+(msg.tag||sub);
var ndata={tag:tagsrc.toString().replace(/[^A-Za-z0-9_]/g,'_'),channel:cat,group:cat};
if(global.get('maintenance_mode')){
  node.send([null,{payload:dub()+'  [maint-dropped] '+title+' — '+message+'\n'}]);
  return null;
}
if(quiet()){
  var held=context.get('held')||[];
  held.push({title:title,message:message,ndata:ndata,firedAt:Date.now()});
  context.set('held',held);
  node.send([null,{payload:dub()+'  [quiet-held] '+title+' — '+message+'\n'}]);
  return null;
}
node.send([{title:title,message:message,ndata:ndata},{payload:dub()+'  '+title+' — '+message+'\n'}]);
return null;

var b=msg.payload; if(typeof b==='string'){try{b=JSON.parse(b);}catch(e){b={};}}
var st=(b.status||'').toLowerCase();
var detail;
if(st==='updated')detail='Updated — config saved to GitHub ('+(b.size||'?')+') at '+(b.timestamp||'?')+'.';
else if(st==='unchanged')detail='Unchanged — no changes since last backup ('+(b.timestamp||'?')+').';
else detail='FAILED — '+(b.error||'Unknown error');
return {cat:'Backup',sub:'TrueNAS-config',message:detail,tag:'tnconfig'};

var b=msg.payload; if(typeof b==='string'){try{b=JSON.parse(b);}catch(e){b={};}}
var t=b.title||'', m=b.message||'';
return {cat:'Backup',sub:'MikroTik',message:(t?t+' — ':'')+m,tag:'mikrotik'};

var b=msg.payload; if(typeof b==='string'){try{b=JSON.parse(b);}catch(e){b={};}}
var ds=b.dataset||'unknown';
return {cat:'Backup',sub:'Restic',message:'Restic backup for '+ds+' on TrueNAS failed. Check /mnt/MainPool/logs/restic_'+ds+'.log',tag:'restic_'+ds};

var b=msg.payload; if(typeof b==='string'){try{b=JSON.parse(b);}catch(e){b={};}}
var detail=(b.status||'?')+': '+(b.name||'?')+' — '+(b.host||'?')+' ['+(b.severity||'?')+'] — '+(b.message||'');
return {cat:'Monitoring',sub:'Zabbix',message:detail,tag:'zabbix_'+((b.name||b.host||'evt'))};

const tok = env.get("PVE_API_TOKEN"); // full PVEAPIToken=... string, from gitignored .env
const base = "https://10.0.0.251:8006/api2/json/nodes/";
const q = "/tasks?typefilter=vzdump&limit=8&source=archive";
const mk = (n) => ({ url: base + n + q, headers: { Authorization: tok }, node: n, topic: "pve" });
node.send([[ mk("proxmox"), mk("proxmox2") ]]);
return null;

const now = Date.now()/1000;
const WINDOW = 26*3600;
const labels = {proxmox:'node1 (proxmox)', proxmox2:'node2 (proxmox2)'};
const fmt = (e) => new Date(e*1000).toLocaleString('en-IE',{timeZone:'Europe/Dublin',weekday:'short',hour:'2-digit',minute:'2-digit'});
let problems = [];
for (const r of msg.payload) {
  const lbl = labels[r.node] || r.node;
  const done = (r.tasks||[]).filter(t => t.endtime);
  const recent = done.filter(t => (now - t.endtime) < WINDOW);
  if (recent.length === 0) { problems.push('\u2022 ' + lbl + ': no backup completed in last 26h'); continue; }
  const failed = recent.filter(t => t.status !== 'OK');
  for (const f of failed) problems.push('\u2022 ' + lbl + ': backup ended \u201c' + f.status + '\u201d at ' + fmt(f.endtime));
}
const stamp = new Date().toLocaleTimeString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',minute:'2-digit'});
if (problems.length === 0) { node.status({fill:'green',shape:'dot',text:'all OK '+stamp}); return null; }
node.status({fill:'red',shape:'dot',text:problems.length+' issue(s) '+stamp});
msg.cat = 'Backup';
msg.sub = 'Proxmox';
msg.message = problems.join('\n');
msg.tag = 'proxmox_backup';
return msg;

const D=(msg.payload&&msg.payload.new_state)?msg.payload.new_state.state:msg.payload;
const on=(D==='on');
global.set('maintenance_mode',on);
node.warn('[maint] maintenance_mode='+D);
return null;

const ents=Array.isArray(msg.payload)?msg.payload:[];
const e=ents.find(x=>x.entity_id==='input_boolean.maintenance_mode');
const on=!!e&&e.state==='on';
const prev=global.get('maintenance_mode');
global.set('maintenance_mode',on);
if(prev===undefined||prev!==on)node.warn('[maint] seed maintenance_mode='+(on?'on':'off'));
return null;

// Add-on polls every 6h; >13h since last successful poll = two misses = stuck
// (04-07-2026: portal ReadTimeout crashed the add-on, sensors froze 2 days unseen).
// NB data_lag (meter-read age, up to ~4 days) is normal - we check the POLL time.
var LIMIT_H = 13;
var REALERT_MS = 6*60*60*1000; // re-alert at most every 6h while still stale
var ents = msg.payload || [];
var st = ents.length ? ents[0].state : null;
var ageH = null;
if (st && st !== 'unknown' && st !== 'unavailable') {
    var t = Date.parse(st);
    if (!isNaN(t)) ageH = (Date.now() - t) / 3600000;
}
var stale = (ageH === null) || (ageH > LIMIT_H);
if (!stale) { context.set('lastAlert', 0); return null; }
var last = context.get('lastAlert') || 0;
if (Date.now() - last < REALERT_MS) return null;
context.set('lastAlert', Date.now());
var detail = (ageH === null)
  ? 'esbn_last_update sensor is ' + (st || 'missing') + ' - add-on may be dead.'
  : 'Last successful ESBN poll was ' + ageH.toFixed(1) + 'h ago (6h cycle, limit ' + LIMIT_H + 'h). Add-on likely crashed on a portal timeout - check/restart esbn-to-mqtt.';
return {cat: 'Service', sub: 'ESBN add-on', message: detail, tag: 'esbn_stale'};
